INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('483', '
<p><strong>จากข้อมูลต่อไปนี้ จงตอบคำถาม</strong></p>
<div class="my-4 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-center text-lg font-math">
  <p>\( \frac{A}{2} \nless B = (C+D) &lt; E \)</p>
  <p>\( I &gt; (M+N) = E &gt; F \)</p>
  <p class="text-sm mt-2 text-gray-600 dark:text-gray-400">ทุกตัวอักษรมีค่ามากกว่า 0</p>
</div>
<p><strong>หลักในการทำคำตอบ</strong><br/>
<strong>ตอบ 1</strong> ถ้าข้อสรุปทั้งสองเป็นจริงตามเงื่อนไข<br/>
<strong>ตอบ 2</strong> ถ้าข้อสรุปทั้งสองเป็นเท็จตามเงื่อนไข<br/>
<strong>ตอบ 3</strong> ถ้าข้อสรุปทั้งสองไม่แน่ชัดตามเงื่อนไข<br/>
<strong>ตอบ 4</strong> ถ้าข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง</p>
<p><strong>78.<br/>ข้อสรุปที่ 1: B &gt; F<br/>ข้อสรุปที่ 2: A &lt; I</strong></p>', '{"A":"ข้อสรุปทั้งสองเป็นจริง","B":"ข้อสรุปทั้งสองเป็นเท็จ","C":"ข้อสรุปทั้งสองไม่สามารถสรุปได้แน่ชัด","D":"ข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง"}', 'C', '<p><strong>ตอบ 3</strong> (ไม่แน่ชัดทั้งคู่)</p><p>ข้อสรุปที่ 1: จาก B &lt; E และ E &gt; F จะได้ทิศทางเครื่องหมายสวนทางกัน (B &lt; E &gt; F) จึงไม่สามารถเปรียบเทียบ B กับ F ได้ชัดเจน (<strong>ไม่แน่ชัด</strong>)<br/>ข้อสรุปที่ 2: จาก E &lt; I และ A/2 ≮ B &lt; E จะเห็นว่ามีเครื่องหมาย ≮ (≥) และ &lt; ผสมกัน (A/2 ≥ B &lt; E &lt; I) ทิศทางเครื่องหมายสวนทางกัน จึงไม่สามารถเปรียบเทียบได้ (<strong>ไม่แน่ชัด</strong>)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เงื่อนไขสัญลักษณ์"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('484', '
<p><strong>จากข้อมูลต่อไปนี้ จงตอบคำถาม</strong></p>
<div class="my-4 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-center text-lg font-math">
  <p>\( \frac{A}{2} \nless B = (C+D) &lt; E \)</p>
  <p>\( I &gt; (M+N) = E &gt; F \)</p>
  <p class="text-sm mt-2 text-gray-600 dark:text-gray-400">ทุกตัวอักษรมีค่ามากกว่า 0</p>
</div>
<p><strong>หลักในการทำคำตอบ</strong><br/>
<strong>ตอบ 1</strong> ถ้าข้อสรุปทั้งสองเป็นจริงตามเงื่อนไข<br/>
<strong>ตอบ 2</strong> ถ้าข้อสรุปทั้งสองเป็นเท็จตามเงื่อนไข<br/>
<strong>ตอบ 3</strong> ถ้าข้อสรุปทั้งสองไม่แน่ชัดตามเงื่อนไข<br/>
<strong>ตอบ 4</strong> ถ้าข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง</p>
<p><strong>79.<br/>ข้อสรุปที่ 1: I &gt; C<br/>ข้อสรุปที่ 2: M &lt; E</strong></p>', '{"A":"ข้อสรุปทั้งสองเป็นจริง","B":"ข้อสรุปทั้งสองเป็นเท็จ","C":"ข้อสรุปทั้งสองไม่สามารถสรุปได้แน่ชัด","D":"ข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง"}', 'A', '<p><strong>ตอบ 1</strong> (เป็นจริงทั้งคู่)</p><p>ข้อสรุปที่ 1: จาก I &gt; E และ E &gt; (C+D) จะได้ I &gt; C+D ซึ่งตัวแปรทุกตัวมีค่ามากกว่า 0 จะได้ I &gt; C แน่นอน (<strong>จริง</strong>)<br/>ข้อสรุปที่ 2: จาก M + N = E เนื่องจากทุกตัวแปรมากกว่า 0 จะได้ M = E - N ดังนั้น M ย่อมน้อยกว่า E เสมอ (<strong>จริง</strong>)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เงื่อนไขสัญลักษณ์"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('485', '
<p><strong>จากข้อมูลต่อไปนี้ จงตอบคำถาม</strong></p>
<div class="my-4 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-center text-lg font-math">
  <p>\( \frac{A}{2} \nless B = (C+D) &lt; E \)</p>
  <p>\( I &gt; (M+N) = E &gt; F \)</p>
  <p class="text-sm mt-2 text-gray-600 dark:text-gray-400">ทุกตัวอักษรมีค่ามากกว่า 0</p>
</div>
<p><strong>หลักในการทำคำตอบ</strong><br/>
<strong>ตอบ 1</strong> ถ้าข้อสรุปทั้งสองเป็นจริงตามเงื่อนไข<br/>
<strong>ตอบ 2</strong> ถ้าข้อสรุปทั้งสองเป็นเท็จตามเงื่อนไข<br/>
<strong>ตอบ 3</strong> ถ้าข้อสรุปทั้งสองไม่แน่ชัดตามเงื่อนไข<br/>
<strong>ตอบ 4</strong> ถ้าข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง</p>
<p><strong>80.<br/>ข้อสรุปที่ 1: A &gt; 2D<br/>ข้อสรุปที่ 2: E ≠ F</strong></p>', '{"A":"ข้อสรุปทั้งสองเป็นจริง","B":"ข้อสรุปทั้งสองเป็นเท็จ","C":"ข้อสรุปทั้งสองไม่สามารถสรุปได้แน่ชัด","D":"ข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง"}', 'A', '<p><strong>ตอบ 1</strong> (เป็นจริงทั้งคู่)</p><p>ข้อสรุปที่ 1: จาก A/2 ≮ C + D (ตีความได้ว่า A/2 ≥ C + D) และทุกตัวแปรมากกว่า 0 จะได้ A/2 &gt; D นำ 2 คูณทั้งสองข้างจะได้ A &gt; 2D (<strong>จริง</strong>)<br/>ข้อสรุปที่ 2: จาก E &gt; F ชัดเจนว่า E ย่อมมีค่าไม่เท่ากับ F (<strong>จริง</strong>)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เงื่อนไขสัญลักษณ์"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('486', '
<p><strong>จากข้อมูลต่อไปนี้ จงตอบคำถาม</strong></p>
<div class="my-4 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-center text-lg font-math">
  <p>\( \frac{A}{2} \nless B = (C+D) &lt; E \)</p>
  <p>\( I &gt; (M+N) = E &gt; F \)</p>
  <p class="text-sm mt-2 text-gray-600 dark:text-gray-400">ทุกตัวอักษรมีค่ามากกว่า 0</p>
</div>
<p><strong>หลักในการทำคำตอบ</strong><br/>
<strong>ตอบ 1</strong> ถ้าข้อสรุปทั้งสองเป็นจริงตามเงื่อนไข<br/>
<strong>ตอบ 2</strong> ถ้าข้อสรุปทั้งสองเป็นเท็จตามเงื่อนไข<br/>
<strong>ตอบ 3</strong> ถ้าข้อสรุปทั้งสองไม่แน่ชัดตามเงื่อนไข<br/>
<strong>ตอบ 4</strong> ถ้าข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง</p>
<p><strong>81.<br/>ข้อสรุปที่ 1: I + E &lt; 2(C+D)<br/>ข้อสรุปที่ 2: C = E</strong></p>', '{"A":"ข้อสรุปทั้งสองเป็นจริง","B":"ข้อสรุปทั้งสองเป็นเท็จ","C":"ข้อสรุปทั้งสองไม่สามารถสรุปได้แน่ชัด","D":"ข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง"}', 'B', '<p><strong>ตอบ 2</strong> (เป็นเท็จทั้งคู่)</p><p>ข้อสรุปที่ 1: จาก C + D &lt; E &lt; I นำ 2 คูณจะได้ 2(C+D) &lt; 2E หรือ 2(C+D) &lt; E + E ซึ่ง E &lt; I ดังนั้น 2(C+D) &lt; E + I ข้อสรุปกล่าวกลับกัน (I + E &lt; 2(C+D)) จึงเป็น <strong>เท็จ</strong><br/>ข้อสรุปที่ 2: จาก E &gt; C + D และทุกตัวแปรมากกว่า 0 จะได้ E &gt; C แน่นอน ข้อสรุปกล่าวว่า C = E จึงเป็น <strong>เท็จ</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เงื่อนไขสัญลักษณ์"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('487', '
<p><strong>จากข้อมูลต่อไปนี้ จงตอบคำถาม</strong></p>
<div class="my-4 p-4 bg-gray-100 dark:bg-gray-800 rounded-lg text-center text-lg font-math">
  <p>\( \frac{A}{2} \nless B = (C+D) &lt; E \)</p>
  <p>\( I &gt; (M+N) = E &gt; F \)</p>
  <p class="text-sm mt-2 text-gray-600 dark:text-gray-400">ทุกตัวอักษรมีค่ามากกว่า 0</p>
</div>
<p><strong>หลักในการทำคำตอบ</strong><br/>
<strong>ตอบ 1</strong> ถ้าข้อสรุปทั้งสองเป็นจริงตามเงื่อนไข<br/>
<strong>ตอบ 2</strong> ถ้าข้อสรุปทั้งสองเป็นเท็จตามเงื่อนไข<br/>
<strong>ตอบ 3</strong> ถ้าข้อสรุปทั้งสองไม่แน่ชัดตามเงื่อนไข<br/>
<strong>ตอบ 4</strong> ถ้าข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง</p>
<p><strong>82.<br/>ข้อสรุปที่ 1: M + C &gt; N + D<br/>ข้อสรุปที่ 2: I &lt; B</strong></p>', '{"A":"ข้อสรุปทั้งสองเป็นจริง","B":"ข้อสรุปทั้งสองเป็นเท็จ","C":"ข้อสรุปทั้งสองไม่สามารถสรุปได้แน่ชัด","D":"ข้อสรุปทั้งสองมีข้อสรุปใดข้อสรุปหนึ่งที่เป็นจริง เป็นเท็จ หรือไม่แน่ชัด ไม่ตรงกับอีกข้อสรุปหนึ่ง"}', 'D', '<p><strong>ตอบ 4</strong> (ข้อสรุปไม่ตรงกัน)</p><p>ข้อสรุปที่ 1: จากเงื่อนไข ไม่สามารถแยกหรือจัดรูปพจน์เพื่อมาเปรียบเทียบ M+C กับ N+D ได้อย่างชัดเจน (<strong>ไม่แน่ชัด</strong>)<br/>ข้อสรุปที่ 2: จากเงื่อนไข B &lt; E &lt; I จะได้ I &gt; B ข้อสรุปกล่าวว่า I &lt; B จึงเป็น <strong>เท็จ</strong></p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เงื่อนไขสัญลักษณ์"]', '2559');
